solution_code:
#include <iostream>
#include <iomanip>

class Celsius {
public:
    explicit Celsius(double v) : m_val{v} {}
    double value() const { return m_val; }
private:
    double m_val{0.0};
};

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        double v;
        std::cin >> v;
        Celsius c{v};
        std::cout << "T=" << std::fixed << std::setprecision(1) << c.value() << "C\n";
    }
}

