#include <iostream>

struct Color {
    int r, g, b;
    explicit Color(int red, int green, int blue)
        : r{red}, g{green}, b{blue} {}
};

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int r, g, b;
        std::cin >> r >> g >> b;
        Color c{r, g, b};
        std::cout << "rgb(" << c.r << "," << c.g << "," << c.b << ")\n";
    }
}
